window.PACTO.acts["dir-2011-36"]={"label": "DIRETTIVA 2011/36/UE DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Dir. 36/2011", "file": "ext-dir-2011-36.html", "external": true, "version": "consolidato 2024-07-14", "eurlex": "https://eur-lex.europa.eu/eli/dir/2011/36/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">La presente direttiva stabilisce norme minime relative alla definizione dei reati e delle sanzioni nell’ambito della tratta di esseri umani. Essa introduce altresì disposizioni comuni, tenendo conto della prospettiva di genere, per rafforzare la prevenzione di tale reato e la protezione delle vittime.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Reati relativi alla tratta di esseri umani", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché siano punibili i seguenti atti dolosi:</p>\n<p class=\"norm inline-element\">il reclutamento, il trasporto, il trasferimento, l’alloggio o l’accoglienza di persone, compreso il passaggio o il trasferimento dell’autorità su queste persone, con la minaccia dell’uso o con l’uso stesso della forza o di altre forme di coercizione, con il rapimento, la frode, l’inganno, l’abuso di potere o della posizione di vulnerabilità o con l’offerta o l’accettazione di somme di denaro o di vantaggi per ottenere il consenso di una persona che ha autorità su un’altra, a fini di sfruttamento.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per posizione di vulnerabilità si intende una situazione in cui la persona in questione non ha altra scelta effettiva ed accettabile se non cedere all’abuso di cui è vittima.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo sfruttamento comprende, come minimo, lo sfruttamento della prostituzione altrui o altre forme di sfruttamento sessuale, il lavoro o i servizi forzati, compreso l'accattonaggio, la schiavitù o pratiche simili alla schiavitù, la servitù, lo sfruttamento di attività illecite o il prelievo di organi, lo sfruttamento della maternità surrogata, del matrimonio forzato o dell'adozione illegale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il consenso della vittima della tratta di esseri umani allo sfruttamento, programmato o effettivo, è irrilevante in presenza di uno dei mezzi indicati al paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La condotta di cui al paragrafo 1, qualora coinvolga minori, è punita come reato di tratta di esseri umani anche in assenza di uno dei mezzi indicati al paragrafo 1. Il presente paragrafo non si applica allo sfruttamento della maternità surrogata di cui al paragrafo 3, a meno che la madre surrogata sia minore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ai fini della presente direttiva per «minore» si intende la persona di età inferiore ai diciotto anni.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Istigazione, favoreggiamento, concorso e tentativo", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Gli Stati membri adottano le misure necessarie affinché siano punibili l’istigazione, il favoreggiamento e il concorso o il tentativo nella commissione dei reati di cui all’articolo 2.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Pene", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché i reati di cui all’articolo 2 siano punibili con la reclusione della durata massima di almeno cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché i reati di cui all’articolo 2 siano punibili con la reclusione della durata massima di almeno dieci anni, laddove tale reato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia stato commesso nei confronti di una vittima particolarmente vulnerabile, compresi, nel contesto della presente direttiva, almeno i minori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia stato commesso nel contesto di un’organizzazione criminale ai sensi della decisione quadro 2008/841/GAI del Consiglio, del 24 ottobre 2008, relativa alla lotta contro la criminalità organizzata (\n<span class=\"superscript\">1</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">abbia messo in pericolo la vita della vittima intenzionalmente o per colpa grave; oppure</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia stato commesso ricorrendo a violenze gravi o abbia causato alla vittima un pregiudizio particolarmente grave, compreso un pregiudizio fisico o psicologico.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nel caso di un reato di cui all'articolo 2, siano considerate circostanze aggravanti, conformemente alle pertinenti disposizioni del diritto nazionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che il reato sia stato commesso da funzionari pubblici nell'esercizio delle loro funzioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che l'autore del reato abbia agevolato o si sia reso responsabile, mediante tecnologie dell'informazione e della comunicazione, della diffusione di immagini, video o materiale analogo di natura sessuale relativo alla vittima.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché i reati di cui all’articolo 3 siano puniti con pene effettive, proporzionate e dissuasive, che possono dar luogo a consegna.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Responsabilità delle persone giuridiche", "anchor": "art_5", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le persone giuridiche possano essere ritenute responsabili dei reati di cui all'articolo 2, all'articolo 3 e all'articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, commessi a loro vantaggio da qualsiasi soggetto, che agisca a titolo individuale o in quanto membro di un organismo della persona giuridica, che detenga una posizione dominante in seno alla persona giuridica, basata:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sul potere di rappresentanza di detta persona giuridica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sul potere di prendere decisioni per conto della persona giuridica; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sull’esercizio del controllo in seno a tale persona giuridica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano inoltre le misure necessarie affinché le persone giuridiche possano essere ritenute responsabili qualora la mancata sorveglianza o il mancato controllo da parte di un soggetto tra quelli descritti al paragrafo 1 abbia reso possibile la commissione, a vantaggio della persona giuridica, di uno dei reati di cui all'articolo 2, all'articolo 3 e all'articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, da parte di una persona sottoposta all'autorità di tale soggetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La responsabilità delle persone giuridiche ai sensi dei paragrafi 1 e 2 non esclude l'avvio di procedimenti penali contro le persone fisiche che abbiano commesso uno dei reati di cui all’articolo 2, all’articolo 3 e all'articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, abbiano istigato qualcuno a commetterli o vi abbiano concorso.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai sensi della presente direttiva, per «persona giuridica» s’intende qualsiasi ente che abbia personalità giuridica in forza del diritto nazionale applicabile, ad eccezione degli Stati o di altre istituzioni pubbliche nell’esercizio dei poteri pubblici e delle organizzazioni internazionali pubbliche.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché la persona giuridica ritenuta responsabile ai sensi dell'articolo 5, paragrafo 1 o 2, sia punibile con sanzioni o misure penali o non penali effettive, proporzionate e dissuasive.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le sanzioni o le misure per le persone giuridiche ritenute responsabili ai sensi dell'articolo 5, paragrafo 1 o 2, per i reati di cui all’articolo 2, all’articolo 3 e all’articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, includano sanzioni pecuniarie penali o non penali e possano comprendere altre sanzioni o misure penali o non penali quali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esclusione dal godimento di benefici o aiuti pubblici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esclusione dall'accesso a finanziamenti pubblici, comprese procedure di gara, sovvenzioni, concessioni e licenze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">interdizione temporanea o permanente dall'esercizio di attività commerciali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ritiro dei permessi e delle autorizzazioni all'esercizio delle attività che hanno portato al reato in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assoggettamento a sorveglianza giudiziaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedimenti giudiziari di scioglimento</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">chiusura delle sedi usate per commettere il reato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">laddove vi sia un pubblico interesse, pubblicazione integrale o parziale della decisione giudiziaria relativa al reato commesso e alle sanzioni o misure imposte, fatte salve le norme in materia di tutela della vita privata e di protezione dei dati personali.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "", "anchor": "art_8", "frags": [[null, "<p class=\"norm\">Gli Stati membri adottano le misure necessarie, conformemente ai principi fondamentali dei loro ordinamenti giuridici, per conferire alle autorità nazionali competenti il potere di non perseguire né imporre sanzioni penali alle vittime della tratta di esseri umani coinvolte in attività criminali o altre attività illecite che sono state costrette a compiere come conseguenza diretta di uno degli atti di cui all'articolo 2.</p>"]]}, "9": {"label": "Articolo 9", "heading": "Indagini e azione penale", "anchor": "art_9", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le indagini o l'azione penale relative ai reati di cui all’articolo 2, all’articolo 3 e all’articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, non siano subordinate alla querela, alla denuncia o all'accusa formulate da una vittima e il procedimento penale possa continuare anche se la vittima ritratta una propria dichiarazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, qualora richiesto dalla natura dell’atto, i reati di cui agli articoli 2 e 3 possano essere perseguiti per un congruo periodo di tempo dopo che la vittima ha raggiunto la maggiore età.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le persone, le unità o i servizi incaricati delle indagini o dell'azione penale per i reati di cui agli articoli 2 e 3 ricevano la formazione necessaria. Gli Stati membri provvedono affinché le persone, le unità o i servizi incaricati delle indagini o dell'azione penale per i reati di cui agli articoli 2 e 3, laddove tali reati siano commessi o agevolati mediante tecnologie dell'informazione o della comunicazione, dispongano di competenze e capacità tecnologiche adeguate. Gli Stati membri sono incoraggiati, ove opportuno e conformemente ai rispettivi ordinamenti giuridici nazionali, a creare unità specializzate in seno alle autorità di contrasto e alle autorità inquirenti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le persone, le unità o i servizi incaricati delle indagini o dell’azione penale per i reati di cui agli articoli 2 e 3 dispongano di strumenti investigativi efficaci, quali quelli utilizzati contro la criminalità organizzata o altri reati gravi.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Giurisdizione", "anchor": "art_10", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie a stabilire la propria giurisdizione per i reati di cui all’articolo 2, all’articolo 3 e all’articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, nei casi seguenti:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reato è stato commesso interamente o parzialmente sul suo territorio; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autore del reato è un suo cittadino.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Uno Stato membro informa la Commissione qualora decida di stabilire la propria giurisdizione anche per i reati di cui all’articolo 2, all’articolo 3 e all’articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, commessi al di fuori del suo territorio, nei casi seguenti:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reato è stato commesso contro uno dei suoi cittadini o contro una persona che risiede abitualmente nel territorio di detto Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reato è stato commesso a vantaggio di una persona giuridica che ha sede nel territorio di detto Stato membro; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autore del reato risiede abitualmente nel territorio di detto Stato membro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le azioni penali relative ai reati di cui agli articoli 2 e 3, commessi al di fuori del territorio dello Stato membro interessato, ciascuno Stato membro adotta, nei casi di cui al paragrafo 1, lettera b), e può adottare, nei casi di cui al paragrafo 2, le misure necessarie affinché la sua giurisdizione non sia subordinata alle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fatti costituiscano reato nel luogo in cui sono stati commessi; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reato sia perseguibile solo su querela da parte della vittima nel luogo in cui è stato commesso, oppure su denuncia dello Stato sul cui territorio il reato è stato commesso.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Assistenza e sostegno alle vittime della tratta di esseri umani", "anchor": "art_11", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le vittime ricevano assistenza specializzata e sostegno, con un approccio incentrato sulle vittime e sensibile alle specificità di genere, delle persone con disabilità e dei minori, prima, durante e per un congruo periodo di tempo successivamente alla conclusione del procedimento penale, per permettere loro di esercitare i diritti sanciti dalla direttiva 2012/29/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n) e dalla presente direttiva.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché una persona riceva assistenza e sostegno non appena le autorità competenti abbiano un ragionevole motivo di ritenere che nei suoi confronti sia stato compiuto uno dei reati di cui agli articoli 2 e 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché l’assistenza e il sostegno alla vittima non siano subordinati alla volontà di quest’ultima di collaborare nelle indagini penali, nel procedimento giudiziario o nel processo, fatte salve la direttiva 2004/81/CE o norme nazionali analoghe.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie ad istituire, mediante disposizioni legislative, regolamentari o amministrative, uno o più meccanismi miranti alla rapida individuazione, all'identificazione, all'assistenza e al sostegno delle vittime identificate e presunte, in collaborazione con le organizzazioni di sostegno pertinenti, e a designare un punto di contatto per l'orientamento transfrontaliero delle vittime.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I compiti dei meccanismi di orientamento che operano conformemente al presente paragrafo comprendono almeno quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilire norme minime per l'individuazione e la rapida identificazione delle vittime, e adattare le procedure di individuazione e identificazione alle varie forme di sfruttamento contemplate dalla presente direttiva;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">orientare la vittima al sostegno e all'assistenza più adeguati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilire accordi di cooperazione o protocolli con le autorità competenti in materia di asilo per garantire che siano forniti assistenza, sostegno e protezione alle vittime della tratta che necessitano anche di protezione internazionale o che desiderano chiedere tale protezione, tenendo conto della situazione individuale della vittima.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le misure di assistenza e sostegno di cui ai paragrafi 1 e 2 sono attuate su base consensuale e informata e prevedono almeno standard di vita in grado di garantire la sussistenza delle vittime, fornendo loro un alloggio adeguato e sicuro, compresi rifugi e altre sistemazioni temporanee adeguate, e assistenza materiale, nonché le cure mediche necessarie, compresi l'assistenza psicologica, la consulenza e le informazioni e, se necessario, i servizi di traduzione ed interpretariato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5 bis.  </span>\n<div class=\"norm inline-element\">I rifugi e altre sistemazioni temporanee adeguate di cui al paragrafo 5 sono messi a disposizione in numero sufficiente e sono facilmente accessibili alle vittime presunte e identificate della tratta. I rifugi e altre sistemazioni temporanee adeguate aiutano le vittime nel percorso di recupero, offrendo loro condizioni di vita adeguate ai fini del ritorno a una vita indipendente. Sono inoltre attrezzate per rispondere alle esigenze specifiche dei minori, compresi quelli vittime della tratta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 5 riguardano, se del caso, il periodo di riflessione e ripresa ai sensi della direttiva 2004/81/CE e informazioni sulla possibilità di concedere protezione internazionale ai sensi del regolamento (UE) 2024/1347 (\n<span class=\"superscript\">3</span>\n) e del regolamento (UE) 2024/1348 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n) o di altri strumenti internazionali o disposizioni nazionali analoghe.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri tengono conto delle esigenze specifiche delle vittime, derivanti in particolare dall’eventuale stato di gravidanza, dallo stato di salute, da eventuali disabilità, disturbi mentali o psicologici, o dalla sottoposizione a gravi forme di violenza psicologia, fisica o sessuale.</div>\n</div>"]]}, "11a": {"label": "Articolo 11 bis", "heading": "", "anchor": "art_11a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono la complementarità e il coordinamento tra le autorità coinvolte nelle attività anti-tratta e le autorità competenti in materia di asilo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le vittime della tratta possano esercitare il diritto di chiedere protezione internazionale o uno status nazionale equivalente, anche quando la vittima riceve assistenza, sostegno e protezione in quanto vittima presunta o identificata della tratta di esseri umani.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Tutela delle vittime della tratta di esseri umani nelle indagini e nei procedimenti penali", "anchor": "art_12", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le misure di protezione di cui al presente articolo si applicano in aggiunta ai diritti sanciti nella direttiva 2012/29/UE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le vittime della tratta di esseri umani abbiano accesso senza indugio alla consulenza legale e, secondo il ruolo delle vittime nel pertinente sistema giudiziario, all’assistenza legale, anche ai fini di una domanda di risarcimento. La consulenza legale e l’assistenza legale sono gratuite se la vittima non dispone di risorse finanziarie sufficienti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le vittime di tratta di esseri umani ricevano adeguata protezione sulla base di una valutazione individuale dei rischi, tra l’altro accedendo ai programmi di protezione delle vittime o ad altre misure analoghe, se necessario e conformemente al diritto o alle procedure nazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fermo restando il diritto alla difesa e in base a una valutazione individuale delle autorità competenti sulla situazione personale della vittima, gli Stati membri provvedono affinché le vittime della tratta di esseri umani beneficino di un trattamento specifico intese a prevenire la vittimizzazione secondaria evitando, per quanto possibile e conformemente al diritto nazionale e alle norme sulla discrezionalità, la prassi o gli orientamenti giudiziari, quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le ripetizioni non necessarie delle audizioni nel corso delle indagini e del procedimento penale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contatto visivo fra le vittime e gli imputati, anche durante le deposizioni, quali audizioni ed esami incrociati, ricorrendo a mezzi adeguati fra cui l’uso di appropriate tecnologie della comunicazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le deposizioni in udienze pubbliche; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le domande non necessarie sulla vita privata.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Disposizioni generali sulle misure di assistenza, sostegno e protezione dei minori vittime della tratta di esseri umani", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I minori vittime della tratta di esseri umani ricevono assistenza, sostegno e protezione. Nell’applicazione della presente direttiva è innanzitutto considerato l’interesse superiore del minore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché, ove l’età della vittima della tratta di esseri umani risulti incerta e vi sia motivo di ritenere che sia un minore, detta persona sia considerata minore al fine di ottenere accesso immediato all’assistenza, al sostegno e alla protezione a norma degli articoli 14 e 15.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le procedure di segnalazione di un reato ai sensi della presente direttiva siano sicure, siano eseguite nel rispetto della riservatezza conformemente al diritto nazionale, siano concepite in modo adatto ai minori e accessibili ad essi, e utilizzino un linguaggio consono all'età e alla maturità dei minori vittime della tratta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "14": {"label": "Articolo 14", "heading": "Assistenza e sostegno alle vittime minorenni", "anchor": "art_14", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le azioni specifiche intese ad assistere e sostenere i minori vittime della tratta di esseri umani, a breve e lungo termine, nel recupero fisico e psico-sociale, siano intraprese a seguito di una valutazione individuale della particolare situazione di ogni minore vittima della tratta, tenendo debito conto del parere, delle esigenze e dei timori del minore, nella prospettiva di trovare una soluzione duratura per lo stesso, prevedendo programmi volti a sostenere la sua transizione verso l'emancipazione e l'età adulta, nell'ottica di prevenirne la re-immissione nella tratta. Entro un termine ragionevole gli Stati membri offrono accesso all'istruzione ai minori vittime della tratta e ai figli delle vittime che beneficiano di assistenza e sostegno a norma dell'articolo 11, conformemente al diritto nazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri nominano un tutore o un rappresentante del minore vittima della tratta di esseri umani a partire dal momento in cui il minore stesso è identificato dalle autorità qualora, in virtù del diritto nazionale, un conflitto di interessi tra il minore e i titolari della responsabilità genitoriale impedisca a questi ultimi di assicurare l'interesse superiore del minore e/o di rappresentare il minore stesso. Gli Stati membri provvedono affinché sia nominato un diverso tutore o rappresentante in caso di conflitto di interessi tra il tutore o il rappresentante e il minore vittima della tratta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano, ove opportuno e possibile, misure intese a fornire assistenza e sostegno alla famiglia del minore vittima della tratta di esseri umani qualora la famiglia si trovi nel territorio degli Stati membri. In particolare, ove possibile e opportuno, gli Stati membri applicano alla famiglia in questione l'articolo 4 della direttiva 2012/29/UE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica senza pregiudizio dell’articolo 11.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Tutela dei minori vittime della tratta di esseri umani nelle indagini e nei procedimenti penali", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nelle indagini e nei procedimenti penali, secondo il ruolo delle vittime nel pertinente sistema giudiziario, le autorità competenti nominino un rappresentante del minore vittima della tratta di esseri umani qualora, ai sensi della normativa nazionale, i titolari della responsabilità genitoriale non siano autorizzati a rappresentare il minore in ragione di un conflitto di interesse con la vittima.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono, secondo il ruolo delle vittime nel pertinente sistema giudiziario, affinché i minori vittime della tratta abbiano accesso senza indugio alla consulenza legale e all’assistenza legale gratuite, anche ai fini di una domanda di risarcimento, a meno che essi dispongano di risorse finanziarie sufficienti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fermi restando i diritti della difesa, gli Stati membri adottano le misure necessarie affinché, nelle indagini e nei procedimenti penali relativi ai reati di cui agli articoli 2 e 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le audizioni del minore abbiano luogo senza ritardi ingiustificati dopo la segnalazione dei fatti alle autorità competenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le audizioni del minore si svolgano, ove necessario, in locali appositi o adattati allo scopo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le audizioni del minore siano effettuate, ove necessario, da o mediante operatori formati a tale scopo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove possibile e opportuno, il minore sia ascoltato sempre dalle stesse persone;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle audizioni sia il più limitato possibile e solo se esse siano strettamente necessarie ai fini delle indagini e del procedimento penale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il minore sia accompagnato da un rappresentante o, se del caso, da un adulto di sua scelta, salvo motivata decisione contraria nei confronti di tale adulto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nelle indagini relative ai reati di cui agli articoli 2 e 3, tutte le audizioni del minore vittima del reato, ovvero del minore testimone dei fatti, possano essere videoregistrate e le videoregistrazioni possano essere utilizzate come prova nel procedimento penale, conformemente alle disposizioni di diritto interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nei procedimenti penali relativi ai reati di cui agli articoli 2 e 3, possa essere disposto che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’udienza si svolga a porte chiuse; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il minore sia ascoltato in aula senza essere fisicamente presente, in particolare ricorrendo ad appropriate tecnologie di comunicazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica senza pregiudizio dell’articolo 12.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Assistenza, sostegno e protezione ai minori non accompagnati vittime della tratta di esseri umani", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché le azioni specifiche intese ad assistere e sostenere i minori vittime della tratta di esseri umani di cui all’articolo 14, paragrafo 1, tengano debito conto della particolare situazione di ogni minore non accompagnato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie per trovare una soluzione duratura basata sulla valutazione caso per caso dell’interesse superiore del minore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, ove necessario, sia nominato un tutore del minore non accompagnato vittima della tratta di esseri umani.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nelle indagini e nei procedimenti penali, secondo il ruolo delle vittime nel pertinente sistema giudiziario, le autorità competenti nominino un rappresentante qualora il minore non sia accompagnato o sia separato dalla famiglia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica senza pregiudizio degli articoli 14 e 15.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "", "anchor": "art_17", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché le vittime della tratta di esseri umani abbiano accesso ai sistemi vigenti di risarcimento delle vittime di reati dolosi violenti. Gli Stati membri possono istituire un fondo nazionale per le vittime o uno strumento analogo, conformemente alla loro legislazione nazionale, al fine di risarcire le vittime.</p>"]]}, "18": {"label": "Articolo 18", "heading": "", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tenendo conto delle specificità delle varie forme di sfruttamento, gli Stati membri adottano misure adeguate, quali istruzione, formazione e campagne di informazione, prestando particolare attenzione, se del caso, alla dimensione online, per scoraggiare e ridurre la domanda che favorisce tutte le forme di sfruttamento correlate alla tratta di esseri umani.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano, tenendo conto della prospettiva di genere e dei minori, anche tramite internet, azioni adeguate quali campagne di informazione e sensibilizzazione e programmi di ricerca e istruzione, compresa la promozione dell'alfabetizzazione digitale e delle competenze digitali, ove opportuno in cooperazione con le pertinenti organizzazioni della società civile e altri portatori di interessi, come il settore privato, intese a sensibilizzare e ridurre il rischio che le persone, soprattutto i minori e le persone con disabilità, diventino vittime della tratta di esseri umani.</div>\n</div>"]]}, "18a": {"label": "Articolo 18 bis", "heading": "", "anchor": "art_18a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché, nel caso di un atto doloso, l'uso di servizi forniti da una vittima del reato di cui all'articolo 2 costituisca reato, qualora la vittima sia sfruttata per prestare tali servizi e qualora l'utente dei servizi sia consapevole del fatto che chi presta il servizio è vittima del reato di cui all'articolo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie affinché i reati introdotti conformemente al paragrafo 1 siano punibili con pene effettive, proporzionate e dissuasive.</div>\n</div>"]]}, "18b": {"label": "Articolo 18 ter", "heading": "", "anchor": "art_18b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri promuovono o offrono una formazione periodica e specializzata agli operatori che possono entrare in contatto con vittime effettive o potenziali della tratta di esseri umani, compresi gli operatori di polizia impegnati in prima linea sul territorio, il personale giudiziario, i servizi di assistenza e sostegno, gli ispettori del lavoro, i servizi sociali e gli operatori sanitari, al fine di consentire loro di prevenire e combattere la tratta di esseri umani ed evitare la vittimizzazione secondaria, nonché di individuare, identificare, assistere, sostenere e proteggere le vittime. Tale formazione è basata sui diritti umani, incentrata sulle vittime e sensibile alle specificità di genere, delle persone con disabilità e dei minori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatte salve l'indipendenza della magistratura e le differenze nell'organizzazione della magistratura in tutta l'Unione, gli Stati membri incoraggiano una formazione sia generale che specializzata per i giudici e le autorità inquirenti coinvolti nei procedimenti penali, al fine di consentire loro di prevenire e combattere la tratta di esseri umani ed evitare la vittimizzazione secondaria, nonché di individuare, identificare, assistere, sostenere e proteggere le vittime. Tale formazione è basata sui diritti umani, incentrata sulle vittime e sensibile alle specificità di genere, delle persone con disabilità e dei minori.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie per istituire coordinatori nazionali anti-tratta o meccanismi equivalenti e fornire loro le adeguate risorse necessarie per espletare efficacemente le loro funzioni. Il coordinatore nazionale anti-tratta o il meccanismo equivalente collabora con i pertinenti organi e organismi nazionali, regionali e locali, in particolare con le autorità di contrasto, con i meccanismi di orientamento nazionali e con le pertinenti organizzazioni della società civile attive nel settore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I compiti dei coordinatori nazionali anti-tratta o dei meccanismi equivalenti comprendono la valutazione delle tendenze della tratta di esseri umani, la misurazione dei risultati delle azioni anti-tratta, anche raccogliendo statistiche in stretta collaborazione con le pertinenti organizzazioni della società civile attive nel settore, e la presentazione di relazioni.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I compiti dei coordinatori nazionali anti-tratta o dei meccanismi equivalenti possono comprendere anche quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’istituzione di piani di risposta di emergenza per prevenire la minaccia della tratta di esseri umani in caso di emergenze gravi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la promozione, il coordinamento e, se del caso, il finanziamento di programmi contro la tratta di esseri umani.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono inoltre istituire organismi indipendenti il cui ruolo può comprendere il monitoraggio dell'attuazione e dell'impatto delle azioni di contrasto della tratta, la presentazione di relazioni su questioni che richiedono un'attenzione particolare da parte delle autorità nazionali competenti e la valutazione delle cause profonde e delle tendenze della tratta di esseri umani. Qualora sia istituito un organismo indipendente, gli Stati membri possono assegnargli uno o più compiti di cui al paragrafo 2.</div>\n</div>"]]}, "19a": {"label": "Articolo 19 bis", "heading": "", "anchor": "art_19a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché sia creato un sistema per la registrazione, la produzione e la fornitura di dati statistici anonimizzati per monitorare l’efficacia dei loro sistemi di repressione dei reati di cui alla presente direttiva.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dati statistici di cui al paragrafo 1 comprendono, come minimo, i dati disponibili a livello centrale riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle vittime registrate identificate e presunte dei reati di cui all’articolo 2, disaggregato per organizzazione che ne ha curato la registrazione, sesso, fascia d’età (minore/adulto), cittadinanza e forma di sfruttamento, conformemente al diritto e alle pratiche nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle persone indagate per i reati di cui all’articolo 2, disaggregato per sesso, fascia d’età (minore/adulto), cittadinanza e forma di sfruttamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle persone imputate per i reati di cui all’articolo 2, disaggregato per sesso, fascia d’età (minore/adulto), cittadinanza, forma di sfruttamento e tipo di decisione finale di avvio dell’azione giudiziaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle decisioni di avvio di un’azione giudiziaria (ossia imputazioni per i reati di cui all’articolo 2, imputazioni per gli altri reati, archiviazioni o non luogo a procedere, altro);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle persone condannate per i reati di cui all’articolo 2, disaggregato per sesso, fascia d’età (minore/adulto) e cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle sentenze (ossia assoluzioni, condanne o altro) per i reati di cui all’articolo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle persone indagate, imputate e condannate per i reati di cui all’articolo 18 <span class=\"italics\">bis</span>, paragrafo 1, disaggregato per sesso e fascia d’età (minore/adulto).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri trasmettono annualmente alla Commissione, in linea di massima entro il 30 settembre e, ove ciò non sia possibile, entro il 31 dicembre di ogni anno, i dati statistici di cui al paragrafo 2 relativi all’anno precedente.</div>\n</div>"]]}, "19b": {"label": "Articolo 19 ter", "heading": "", "anchor": "art_19b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 15 luglio 2028, gli Stati membri adottano i loro piani d'azione nazionali anti-tratta, elaborati e attuati in consultazione con i coordinatori nazionali anti-tratta o i meccanismi equivalenti di cui all'articolo 19, gli organismi indipendenti e i pertinenti portatori di interessi attivi nel settore della prevenzione e della repressione della tratta di esseri umani. Gli Stati membri provvedono affinché i piani d'azione nazionali anti-tratta siano riesaminati e aggiornati a intervalli regolari non superiori a cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I piani d'azione nazionali anti-tratta possono comprendere gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">obiettivi, priorità e misure per contrastare la tratta di esseri umani finalizzata a tutte le forme di sfruttamento, comprese misure specifiche per i minori vittime della tratta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure preventive, ad esempio azioni nel settore dell'istruzione e della formazione e campagne di sensibilizzazione, e misure preventive nell'ambito della risposta di emergenza ai rischi della tratta di esseri umani causati da crisi umanitarie, se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure volte a rafforzare la lotta contro la tratta di esseri umani, anche per migliorare le indagini e l'azione penale nei casi di tratta di esseri umani e la cooperazione transfrontaliera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure volte a rafforzare la rapida identificazione, l'assistenza, il sostegno e la protezione delle vittime della tratta di esseri umani;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure per monitorare e valutare periodicamente l'attuazione dei piani d'azione nazionali anti-tratta.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione i rispettivi piani d'azione nazionali anti-tratta, ed eventuali aggiornamenti degli stessi, entro tre mesi dalla loro adozione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I piani d'azione nazionali anti-tratta sono accessibili al pubblico.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per contribuire a una strategia coordinata e consolidata dell'Unione contro la tratta di esseri umani, gli Stati membri facilitano i compiti del coordinatore anti-tratta dell'UE. In particolare gli Stati membri trasmettono al coordinatore anti-tratta dell'UE le informazioni di cui all'articolo 19.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al fine di garantire un approccio coerente e globale, il coordinatore anti-tratta dell'UE assicura il coordinamento con i coordinatori nazionali anti-tratta o i meccanismi equivalenti, gli organismi indipendenti, le agenzie dell'Unione e le pertinenti organizzazioni della società civile attive nel settore, anche ai fini del contributo del coordinatore anti-tratta dell'UE alle relazioni presentate dalla Commissione ogni due anni in merito ai progressi compiuti nella lotta alla tratta di esseri umani.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Sostituzione della decisione quadro 2002/629/GAI", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">La decisione quadro 2002/629/GAI sulla lotta alla tratta di esseri umani è sostituita in relazione agli Stati membri che partecipano all’adozione della presente direttiva, fatti salvi gli obblighi degli Stati membri relativi ai termini per il recepimento della decisione quadro nel diritto nazionale.</p>"], [null, "<p class=\"norm\">In relazione agli Stati membri che partecipano all’adozione della presente direttiva, i riferimenti alla decisione quadro 2002/629/GAI si intendono fatti alla presente direttiva.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Recepimento", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri mettono in vigore le disposizioni legislative, regolamentari e amministrative necessarie per conformarsi alla presente direttiva entro il 6 aprile 2013.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione il testo delle disposizioni che recepiscono nei rispettivi ordinamenti nazionali gli obblighi imposti dalla presente direttiva.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando gli Stati membri adottano tali misure, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all’atto della pubblicazione ufficiale. Le modalità di tale riferimento sono decise dagli Stati membri.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Relazione", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 6 aprile 2015, la Commissione presenta al Parlamento europeo ed al Consiglio una relazione in cui valuta in che misura gli Stati membri abbiano adottato le misure necessarie per conformarsi alla presente direttiva, compresa una descrizione delle misure adottate ai sensi dell’articolo 18, paragrafo 4, corredata se del caso di proposte legislative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 6 aprile 2016, la Commissione presenta una relazione, corredata se del caso di proposte opportune, al Parlamento europeo e al Consiglio, che valuta l’impatto sulla prevenzione della tratta di esseri umani, della legislazione nazionale vigente che incrimina l’utilizzo di servizi che costituiscono oggetto dello sfruttamento legato alla tratta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 15 luglio 2030, la Commissione presenta al Parlamento europeo e al Consiglio una relazione in cui valuta in che misura gli Stati membri abbiano adottato le misure necessarie per conformarsi alla presente direttiva e l'impatto di tali misure.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "24": {"label": "Articolo 24", "heading": "Entrata in vigore", "anchor": "art_24", "frags": [[null, "<p class=\"norm\">La presente direttiva entra in vigore il giorno della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Destinatari", "anchor": "art_25", "frags": [[null, "<p class=\"norm\">Gli Stati membri sono destinatari della presente direttiva conformemente ai trattati.</p>"]]}}, "recitals": {}};